import{c as t,Q as a,j as n,m as r}from"./chunks/framework.DpF7k2f3.js";const p=JSON.parse('{"title":"Chapter 6: RAG - Retrieval Augmented Generation","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part2-fundamentals/chapter6.md","filePath":"en/part2-fundamentals/chapter6.md","lastUpdated":1779671667000}'),o={name:"en/part2-fundamentals/chapter6.md"};function i(s,e,l,u,h,d){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="chapter-6-rag-retrieval-augmented-generation" tabindex="-1">Chapter 6: RAG - Retrieval Augmented Generation <a class="header-anchor" href="#chapter-6-rag-retrieval-augmented-generation" aria-label="Permalink to &quot;Chapter 6: RAG - Retrieval Augmented Generation&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>If Chapter 5 taught you &quot;how to make LLMs listen to you,&quot; then this chapter teaches you &quot;how to make LLMs know things they originally didn&#39;t.&quot;</p><p>RAG (Retrieval-Augmented Generation) is one of the most core technologies in AI application development. When you go for interviews, 80% will ask about RAG; when you build projects, nine out of ten require RAG. The reason is simple: no matter how powerful LLMs are, they have knowledge boundaries—they don&#39;t know your company&#39;s internal documents, don&#39;t understand your unique business processes, and can&#39;t use your latest product data. RAG is the solution.</p><p>But many students only learned the surface of RAG—knowing vector search, chunking documents casually, tuning a few parameters and thinking that&#39;s enough. Interviewers can probe deeper: How do you do reranking? Why would you use semantic chunking instead of recursive chunking in this scenario? What&#39;s the difference between Self-RAG and CRAG? How do you handle multimodal documents?</p><p>After reading this chapter:</p><ul><li>Deeply understand RAG&#39;s essence: not just &quot;retrieval + generation,&quot; but a systematic approach to solving knowledge boundary problems</li><li>Master N types of text chunking strategies: recursive, semantic, Parent-Child, and when to use which</li><li>Choose the right Embedding model: Which Chinese Embeddings are best in 2026, when to fine-tune</li><li>Master retrieval strategies: hybrid search, reranking, query rewriting, adaptive retrieval</li><li>Understand advanced RAG architectures: Self-RAG, CRAG, Multi-hop RAG, Agentic RAG, Multimodal RAG</li></ul><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter6.html">阅读中文版</a></p></blockquote>',9)])])}const m=t(o,[["render",i]]);export{p as __pageData,m as default};
